import React, { useRef, useEffect } from 'react';
import 'ol/ol.css';
import MapOL from 'ol/Map';
import View from 'ol/View';
import TileLayer from 'ol/layer/Tile';
import XYZ from 'ol/source/XYZ'; // अब इसका इस्तेमाल नीचे हो रहा है
import { fromLonLat } from 'ol/proj';
import './Map.css';

const Map = props => {
  const mapRef = useRef();
  const mapInstance = useRef();

  const { center, zoom } = props;

  useEffect(() => {
    // अगर मैप पहले से बना है, तो दोबारा न बनाएं, बस लोकेशन अपडेट करें
    if (mapInstance.current) {
      mapInstance.current.getView().setCenter(fromLonLat([center.lng, center.lat]));
      mapInstance.current.getView().setZoom(zoom);
      return; 
    }

    // मैप पहली बार लोड करने के लिए
    mapInstance.current = new MapOL({
      target: mapRef.current,
      layers: [
        new TileLayer({
          // XYZ का उपयोग करने से भाषा और टाइल्स बेहतर लोड होते हैं
          source: new XYZ({
            url: 'https://tile.openstreetmap.org/{z}/{x}/{y}.png'
          })
        })
      ],
      view: new View({
        center: fromLonLat([center.lng, center.lat]),
        zoom: zoom
      })
    });
  }, [center, zoom]);

  return (
    <div
      ref={mapRef}
      className={`map ${props.className}`}
      style={props.style}
      onClick={(e) => e.stopPropagation()}
    />
  );
};

export default Map;
